      /* <flatten type="Javascript"> */
function active$VoucherFilter$(f) {
  f.add_onResponseComplete(on$Filter$ResponseComplete);
  changeLookupReadonly(f, 'ma_dvcs');
  if (!f.getItemValue('ky')) onChange$Filter$DateTo(f.getItem('den_ngay'));
}
function close$VoucherFilter$(f) {try {f.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}}
function on$Filter$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result, g = f.grid;
  switch (context) {
    case 'Checking':
      var x = f.getItemValue('mau_bc'), dTo = f.getItem('den_ngay').value;
      g._hiddenForms = [
        {Form: [1, 2, 4, 5, 7, 8, 10, 11, 14, 15, 17, 18, 20, 21, 23, 24], Value: (x == '10' || x == '40')},
        {Form: [0, 1, 3, 4, 6, 7, 9, 10, 13, 14, 16, 17, 19, 20, 22, 23], Value: (x == '20' || x == '50')},
        {Form: [0, 2, 3, 5, 6, 8, 9, 11, 13, 15, 16, 18, 19, 21, 22, 24], Value: (x == '30' || x == '60')}
      ];

      g._ValueFormType = x;
      g._hiddenFields = [{Fields: 'tien_nt, tien_nt0', Value: (x == '10' || x == '20' || x == '30')}];
      x = f.getItem('form').selectedIndex, y = f.getItem('form').options;
      var formName = y[x].text;
      g._alterTitle = [null, [['%f1', formName, true], ['%d2', dTo, true]]];
      if (g._fields.length > 0) try {init$GridReport$(g);} catch (ex) {};

      if (!g._v) g._v = g._ValueFormType;
      if (g._v != g._ValueFormType) {
        remove$GridReport$Filter(g);
        g._v = g._ValueFormType;
      }
      break;
    default:
      break;
  }
}
function onChange$Filter$DateTo(o) {
  var f = o.parentForm, d = f.getItemValue('den_ngay', null, null, true);
  f.setItemValue('ky', Math.ceil((d.getMonth() + 1)/3).toString());
  f.setItemValue('nam', d.getFullYear());
}
function initForm(f) {
  var o = f.getItem('form'), value = f._itemValue.split(String.fromCharCode(255)), text = f._itemText.split(String.fromCharCode(255)), index;
  for (var i = 0; i < value.length; i++) {
    o.options[i] = new Option(text[i], value[i]);
    if (!index && f._defaultForm == value[i]) index = i;
  }
  if (!index) index = 0;
  o.options[index].selected = true;
}
function remove$GridReport$Filter(g) {
  var r = ('tien, tien_nt').split(','), name, field;
  for (i = 0; i < r.length; i++) {
    for (var j = 0; j < g._filter.length; j++) {
      name = $func.trim(r[i]);
      field = $func.findField(name, g._fields)
      if (field) field.FilterPanelValue = '';
      if (g._filter[j].match(/^(\w+):/)[1] == name) {
        Array.removeAt(g._filter, j);
        break;
      }
    }
  }
}
